tokens jaspi (base-color:Blue,background-color:Light,menu-color:Dark)
{
	#colors
	{
		#region RegularColors
            AzulRegular: #28A8EE;
            NeutroRegular: #333333;
		#endregion

        #region Status
            Alerta1: #FDCA40;
            Erro1: #DF2935;
            Sucesso1: #629460;
        #endregion

        #region DarkColors
            AzulDark: #0F80BD;

        #endregion

        #region Cinza
            Cinza1: #A3A3A3;
            Cinza2: #666666;
            Cinza3: #474747;
            Cinza4: #333333;
            Cinza5: #0A0A0A;
        #endregion
	}

	#fonts  {
		Normal: Open Sans;
	}

	//TYPOGRAPHY -> Font Sizes
	#fontSizes  {
		xs: 11px;
		s: 14px;
		m: 18px;
		l: 22px;
		xl: 28px;
		xxl: 34px;
	}
}

styles WorkWithPlusDS
{
    @import WorkWithPlusThemeDS_Work;
	@import WWPBaseObjects.WorkWithPlusBaseDS;

    @font-face
    {
        font-family: 'Open Sans'; 
        src: gx-file(Open Sans Regular);
    }

    .backimage {
        // background-image: gx-image(backgroundImageMountainTeste);
        padding-left: 15px;
    }

    .jcard-blur {
        backdrop-filter: blur(3px);
        background-color: rgba(255, 255, 255, 0.1);
        border: 1px solid rgba(0, 0, 0, 0.2);
        border-radius: 10px;
        box-shadow: 2px 2px 4px rgba(0, 0, 0, 0.25);
        min-height: 140px;
        min-width: 180px;
        max-width: 300px;
        position: relative;
        transition: transform 250ms;
        margin-left: 10px;
        margin-top: 10px;
        padding: 5px;
        word-wrap: break-word;
        word-break: break-all;
    }

    .jcard-icon3 {
        font-size: 56px;
        color: $colors.Cinza3;
    }

    .jcard-title {
        font-family: $fonts.Normal;
        font-size: $fontSizes.s;
        font-weight: 600;
    }

    .jcard-subtitle {
        font-family: $fonts.Normal;
        font-size: $fontSizes.xs;
        font-weight: 300;
    }

    .ionline {
        color: $colors.Sucesso1;
    }

    .ioffline {
        color: $colors.Erro1;
    }

    .iwarning {
        color: $colors.Alerta1;
    }

    .btnicon-neutro3 {
        color: $colors.Cinza3;
        font-size: $fontSizes.l;
    }


    .gap5
    {
        gap: 5px;
    }
    .gap10
    {
        gap: 10px;
    }
    .gap15
    {
        gap: 15px;
    }
    .gap
    {
        @includes gap10;
    }

    .xGridLimitContent
    {
        width: 500px;
        max-width: 100%;
        white-space: nowrap;
        text-overflow: ellipsis;
        display: inline-block !important;
    }
    .WorkWith TR:not(.WCD_tr) span.AttributeRealWidth.xGridLimitContent
    {
        overflow-y: scroll !important;overflow-x: hidden !important;height: 150px;max-height: 150px;
    }
}
